/* 
============================================================
   BASE DE DATOS: VETERINARIA
============================================================ 
DROP TABLE DETALLE_CONSULTAS CASCADE CONSTRAINTS;
DROP TABLE VACUNA_APLICADAS CASCADE CONSTRAINTS;
DROP TABLE CONSULTAS CASCADE CONSTRAINTS;
DROP TABLE MASCOTAS CASCADE CONSTRAINTS;
DROP TABLE CLIENTES CASCADE CONSTRAINTS;
DROP TABLE VETERINARIOS CASCADE CONSTRAINTS;
DROP TABLE ESPECIALIDADES CASCADE CONSTRAINTS;
DROP TABLE VACUNAS CASCADE CONSTRAINTS;
DROP TABLE PRODUCTOS CASCADE CONSTRAINTS;
*/

CREATE TABLE CLIENTEs (
    ID_CLIENTE      NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE          VARCHAR2(60)NOT NULL,
    APELLIDO        VARCHAR2(60)NOT NULL,
    DNI             VARCHAR2(20),
    TELEFONO        VARCHAR2(30),
    EMAIL           VARCHAR2(100)UNIQUE,
    DIRECCION       VARCHAR2(150),
    FECHA_ALTA      DATE DEFAULT SYSDATE,
    CONSTRAINT CHK_CLIENTE_EMAIL CHECK (EMAIL IS NULL OR EMAIL LIKE '%@%')
);

CREATE TABLE ESPECIALIDADES (
    ID_ESPECIALIDAD   NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE             VARCHAR2(60)  NOT NULL UNIQUE,
    DESCRIPCION        VARCHAR2(200)
);

CREATE TABLE VETERINARIOS (
    ID_VETERINARIO   NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE           VARCHAR2(60)     NOT NULL,
    APELLIDO         VARCHAR2(60)     NOT NULL,
    MATRICULA        VARCHAR2(30)     UNIQUE NOT NULL,
    TELEFONO         VARCHAR2(30),
    EMAIL            VARCHAR2(100),
    ID_ESPECIALIDAD  NUMBER(10),
    FECHA_INGRESO    DATE             DEFAULT SYSDATE,
    ACTIVO           CHAR(1)          DEFAULT 'S' CHECK (ACTIVO IN ('S','N')),
    CONSTRAINT FK_VET_ESPECIALIDAD FOREIGN KEY (ID_ESPECIALIDAD)
        REFERENCES ESPECIALIDADES (ID_ESPECIALIDAD)
);

CREATE TABLE MASCOTAS (
    ID_MASCOTA       NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE           VARCHAR2(60)    NOT NULL,
    ESPECIE          VARCHAR2(40)    NOT NULL,   -- Perro, Gato, Ave, etc.
    RAZA             VARCHAR2(60),
    SEXO             CHAR(1)         CHECK (SEXO IN ('M','H')),
    FECHA_NACIMIENTO DATE,
    PESO_KG          NUMBER(5,2),
    COLOR            VARCHAR2(40),
    ESTERILIZADO     CHAR(1)         DEFAULT 'N' CHECK (ESTERILIZADO IN ('S','N')),
    ID_CLIENTE       NUMBER(10)      NOT NULL,
    FECHA_ALTA       DATE            DEFAULT SYSDATE,
    CONSTRAINT FK_MASCOTA_CLIENTE FOREIGN KEY (ID_CLIENTE)REFERENCES CLIENTES (ID_CLIENTE)
);

CREATE TABLE CONSULTAS (
    ID_CONSULTA      NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    ID_MASCOTA       NUMBER(10)      NOT NULL,
    ID_VETERINARIO   NUMBER(10)      NOT NULL,
    FECHA_HORA       DATE            DEFAULT SYSDATE NOT NULL,
    MOTIVO           VARCHAR2(200),
    DIAGNOSTICO      VARCHAR2(500),
    TRATAMIENTO      VARCHAR2(500),
    PESO_REGISTRADO  NUMBER(5,2),
    COSTO            NUMBER(10,2)    DEFAULT 0,
    ESTADO           VARCHAR2(20)    DEFAULT 'PENDIENTE'
                       CHECK (ESTADO IN ('PENDIENTE','EN_CURSO','FINALIZADA','CANCELADA')),
    CONSTRAINT FK_CONSULTA_MASCOTA FOREIGN KEY (ID_MASCOTA)
        REFERENCES MASCOTAS (ID_MASCOTA),
    CONSTRAINT FK_CONSULTA_VETERINARIO FOREIGN KEY (ID_VETERINARIO)
        REFERENCES VETERINARIOS (ID_VETERINARIO)
);

CREATE TABLE VACUNAS (
    ID_VACUNA        NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE           VARCHAR2(80)    NOT NULL UNIQUE,
    ESPECIE_OBJETIVO VARCHAR2(40),
    DOSIS_TOTALES    NUMBER(3)       DEFAULT 1,
    PRECIO           NUMBER(10,2)    DEFAULT 0
);

CREATE TABLE VACUNA_APLICADAS (
    ID_VAC_APLICADA  NUMBER(10)GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    ID_MASCOTA       NUMBER(10)      NOT NULL,
    ID_VACUNA        NUMBER(10)      NOT NULL,
    ID_VETERINARIO   NUMBER(10),
    FECHA_APLICACION DATE            DEFAULT SYSDATE,
    NUMERO_DOSIS     NUMBER(3)       DEFAULT 1,
    PROXIMA_DOSIS    DATE,
    CONSTRAINT FK_VACAPLIC_MASCOTA FOREIGN KEY (ID_MASCOTA)
        REFERENCES MASCOTAS (ID_MASCOTA)
        ON DELETE CASCADE,
    CONSTRAINT FK_VACAPLIC_VACUNA FOREIGN KEY (ID_VACUNA)
        REFERENCES VACUNAS (ID_VACUNA),
    CONSTRAINT FK_VACAPLIC_VETERINARIO FOREIGN KEY (ID_VETERINARIO)
        REFERENCES VETERINARIOS (ID_VETERINARIO)
);

CREATE TABLE PRODUCTOS (
    ID_PRODUCTO      NUMBER(10) GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    NOMBRE           VARCHAR2(100)   NOT NULL,
    TIPO             VARCHAR2(40),    -- Medicamento, Alimento, Insumo
    STOCK            NUMBER(10)      DEFAULT 0,
    PRECIO_UNITARIO  NUMBER(10,2)    DEFAULT 0
);

CREATE TABLE DETALLE_CONSULTAS (
    ID_DETALLE       NUMBER(10) GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    ID_CONSULTA      NUMBER(10)      NOT NULL,
    ID_PRODUCTO      NUMBER(10)      NOT NULL,
    CANTIDAD         NUMBER(6)       DEFAULT 1,
    PRECIO_UNITARIO  NUMBER(10,2)    NOT NULL,
    CONSTRAINT FK_DETALLE_CONSULTA FOREIGN KEY (ID_CONSULTA)
        REFERENCES CONSULTAS (ID_CONSULTA)
        ON DELETE CASCADE,
    CONSTRAINT FK_DETALLE_PRODUCTO FOREIGN KEY (ID_PRODUCTO)
        REFERENCES PRODUCTOS (ID_PRODUCTO)
);

